arguments.file_text:
@typeparam TItem

@if (_items.Count == 0)
{
    if (EmptyTemplate is not null)
    {
        @EmptyTemplate
    }
    else
    {
        <p>No items to display.</p>
    }
}
else
{
    <table>
        @if (HeaderTemplate is not null)
        {
            <thead>
                <tr>@HeaderTemplate</tr>
            </thead>
        }
        <tbody>
            @foreach (var item in _items)
            {
                <tr @key="item" @onclick="() => HandleRowClick(item)">
                    @if (RowTemplate is not null)
                    {
                        @RowTemplate(item)
                    }
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private IReadOnlyList<TItem> _items = Array.Empty<TItem>();

    [Parameter, EditorRequired] public IReadOnlyList<TItem> Items { get; set; } = Array.Empty<TItem>();
    [Parameter] public RenderFragment? HeaderTemplate { get; set; }
    [Parameter] public RenderFragment<TItem>? RowTemplate { get; set; }
    [Parameter] public RenderFragment? EmptyTemplate { get; set; }
    [Parameter] public EventCallback<TItem> OnRowClick { get; set; }

    protected override void OnParametersSet()
    {
        _items = Items ?? Array.Empty<TItem>();
    }

    private async Task HandleRowClick(TItem item)
    {
        if (OnRowClick.HasDelegate)
        {
            await OnRowClick.InvokeAsync(item);
        }
    }
}

